     , (@parent_id, 1, 10 /* Tell */, 3, 1, NULL, 'It speaks of battalions converging in Neftet. The Commanders are taking post on the top of plateaus.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL)
